css:
body {
  font-size: 12px;
  color: #d5c4a1;
  background-color: #282828;
}
body .status-modified {
  color: #98971a;
}
body ::-webkit-scrollbar {
  width: 7px;
}
body ::-webkit-scrollbar-track {
  box-shadow: inset 0 0 6px #282828;
}
body ::-webkit-scrollbar-thumb {
  background-color: #3c3836;
}
body ::-webkit-scrollbar-thumb:window-inactive {
  background-color: #282828;
}
atom-pane {
  border-right: 1px solid #1d2021;
}
atom-pane:last-child {
  border-right: none;
}
.btn {
  color: #ded1b6;
  background-color: #504945;
}
.btn:hover,
.btn:focus {
  color: #fbf1c7;
  background-color: #665c54;
}
.btn:active {
  color: rgba(213, 196, 161, 0.66);
  background-color: #4b4440;
}
.btn.selected {
  color: #d5c4a1;
  background-color: #665c54;
}
.btn:focus,
.btn:focus:active {
  outline: none;
}
.btn.btn-primary {
  color: #d5c4a1;
  background-color: #458588;
}
.btn.btn-primary:hover,
.btn.btn-primary:focus {
  background-color: #4c9296;
}
.btn.btn-primary:active {
  background-color: #3e787a;
}
.btn.btn-primary.selected {
  background-color: #4c9296;
}
.btn.btn-primary.selected:focus,
.btn.btn-primary.selected:hover {
  background-color: #539fa3;
}
.btn.btn-info {
  color: #d5c4a1;
  background-color: #458588;
}
.btn.btn-info:hover,
.btn.btn-info:focus {
  background-color: #4c9296;
}
.btn.btn-info:active {
  background-color: #3e787a;
}
.btn.btn-info.selected {
  background-color: #4c9296;
}
.btn.btn-info.selected:focus,
.btn.btn-info.selected:hover {
  background-color: #539fa3;
}
.btn.btn-success {
  color: #d5c4a1;
  background-color: #689d6a;
}
.btn.btn-success:hover,
.btn.btn-success:focus {
  background-color: #74a576;
}
.btn.btn-success:active {
  background-color: #5f9261;
}
.btn.btn-success.selected {
  background-color: #74a576;
}
.btn.btn-success.selected:focus,
.btn.btn-success.selected:hover {
  background-color: #81ad82;
}
.btn.btn-warning {
  color: #d5c4a1;
  background-color: #d65d0e;
}
.btn.btn-warning:hover,
.btn.btn-warning:focus {
  background-color: #e9650f;
}
.btn.btn-warning:active {
  background-color: #c3550d;
}
.btn.btn-warning.selected {
  background-color: #e9650f;
}
.btn.btn-warning.selected:focus,
.btn.btn-warning.selected:hover {
  background-color: #f0701d;
}
.btn.btn-error {
  color: #d5c4a1;
  background-color: #cc241d;
}
.btn.btn-error:hover,
.btn.btn-error:focus {
  background-color: #de2720;
}
.btn.btn-error:active {
  background-color: #ba211a;
}
.btn.btn-error.selected {
  background-color: #de2720;
}
.btn.btn-error.selected:focus,
.btn.btn-error.selected:hover {
  background-color: #e23730;
}
.btn-group > .btn {
  border-color: rgba(0, 0, 0, 0.2);
}
atom-text-editor[mini] {
  padding-left: 5px;
  color: #d5c4a1;
  border-radius: 2px;
  background-color: #3c3836;
}
atom-text-editor[mini] .placeholder-text {
  color: #bdae93;
}
atom-text-editor[mini] .selection .region {
  background-color: #3c3836;
}
atom-text-editor .gutter .line-number.cursor-line {
  color: #d65d0e;
}
.find-and-replace {
  border-top: 1px solid #1d2021;
}
.status {
  color: #d5c4a1;
}
.status-added {
  color: #8ec07c;
}
.status-ignored {
  color: #bdae93;
}
.status-modified {
  color: #fabd2f;
}
.status-removed {
  color: #fb4934;
}
.status-renamed {
  color: #83a598;
}
.key-binding {
  display: inline-block;
  margin-left: 1px;
  padding: 0 5px;
  line-height: 2;
  font-family: 'Helvetica Neue', Arial, sans-serif;
  font-size: .8em;
  letter-spacing: 1px;
  border-radius: 2px;
  background-color: #282828;
}
.list-group li {
  padding-left: 5px;
}
.list-group li.selected {
  color: #d5c4a1;
  background-color: #3c3836;
}
.list-group li.selected:before {
  display: none;
}
.list-tree .selected {
  color: #d5c4a1;
}
.select-list li {
  padding: 5px 10px;
}
.select-list .status {
  float: right;
}
.select-list.popover-list {
  padding: 5px;
  border-radius: 2px;
  background-color: #3c3836;
  box-shadow: 0 2px 8px 1px rgba(0, 0, 0, 0.3);
}
.select-list.popover-list .list-group {
  margin-top: 5px;
}
.select-list.popover-list .list-group li {
  padding-left: 5px;
}
.select-list.popover-list .list-group li.selected {
  background-color: #504945;
}
.panel-heading {
  border-bottom: 1px solid #1d2021;
  background-color: #3c3836;
}
.inset-panel {
  background-color: #3c3836;
}
.inset-panel .panel-heading {
  background-color: #474240;
}
atom-panel.modal {
  border: 1px solid #1d2021;
  border-top: none;
  box-shadow: 0 2px 8px 1px rgba(0, 0, 0, 0.3);
}
atom-panel.modal .select-list .selected {
  background-color: #504945;
}
.settings-view.pane-item {
  background-color: #32302f;
}
.loading-spinner-large {
  display: block;
  width: 64px;
  height: 64px;
  background-image: url(images/octocat-spinner-128.gif);
  background-repeat: no-repeat;
  background-size: 64px 64px;
}
.loading-spinner-large.inline-block {
  display: inline-block;
}
.loading-spinner-medium {
  display: block;
  width: 48px;
  height: 48px;
  background-image: url(images/octocat-spinner-128.gif);
  background-repeat: no-repeat;
  background-size: 48px 48px;
}
.loading-spinner-medium.inline-block {
  display: inline-block;
}
.loading-spinner-small {
  display: block;
  width: 32px;
  height: 32px;
  background-image: url(images/octocat-spinner-128.gif);
  background-repeat: no-repeat;
  background-size: 32px 32px;
}
.loading-spinner-small.inline-block {
  display: inline-block;
}
.loading-spinner-tiny {
  display: block;
  width: 16px;
  height: 16px;
  background-image: url(images/octocat-spinner-128.gif);
  background-repeat: no-repeat;
  background-size: 16px 16px;
}
.loading-spinner-tiny.inline-block {
  display: inline-block;
}
.ui-site-1 {
  background-color: #458588;
}
.ui-site-2 {
  background-color: #689d6a;
}
.ui-site-3 {
  background-color: #d65d0e;
}
.ui-site-4 {
  background-color: #b16286;
}
.ui-site-5 {
  background-color: #d79921;
}
.status-bar {
  font-size: 12px;
  color: #d5c4a1;
  border-top: 1px solid #1d2021;
  background-color: #282828;
}
.status-bar .git-view .git-branch {
  color: #d65d0e;
}
.status-bar .grammar-status a {
  color: #689d6a;
}
.tab-bar {
  background-color: #282828;
  border-bottom: 1px solid #1d2021;
}
.tab-bar .tab {
  color: #d5c4a1;
  height: 25px;
  line-height: 25px;
  font-size: 12px;
  border-right: 1px solid #1d2021;
  background-color: #282828;
}
.tab-bar .tab.active {
  color: #d5c4a1;
  background-color: #3c3836;
}
.tab-bar .tab.modified {
  color: #98971a;
}
.tab-bar .tab.modified:not(:hover) .close-icon {
  top: 50%;
  right: 14px;
  margin-top: -3px;
  border-color: #689d6a;
}
.tab-bar .tab.modified:hover .close-icon {
  color: #d65d0e;
}
.tab-bar .tab .close-icon:hover {
  color: #d5c4a1;
}
.tab-bar .tab.active .close-icon:hover {
  color: #d5c4a1;
}
.tab-bar .tab.is-dragging {
  background: #0e0e0e;
  border-color: transparent;
  opacity: .5;
}
.tab-bar .tab.is-dragging .close-icon {
  visibility: hidden;
}
.text-smaller {
  font-size: smaller;
}
.text-subtle {
  color: #bdae93;
}
.text-highlight {
  color: #fbf1c7;
}
.text-info {
  color: #83a598;
}
.text-success {
  color: #8ec07c;
}
.text-warning {
  color: #fabd2f;
}
.text-error {
  color: #fb4934;
}
.highlight {
  padding: 1px 4px;
  color: #fbf1c7;
  border-radius: 2px;
  background-color: #3c3836;
}
.highlight-info {
  padding: 1px 4px;
  color: #fbf1c7;
  border-radius: 2px;
  background-color: #458588;
}
.highlight-warning {
  padding: 1px 4px;
  color: #fbf1c7;
  border-radius: 2px;
  background-color: #d65d0e;
}
.highlight-error {
  padding: 1px 4px;
  color: #fbf1c7;
  border-radius: 2px;
  background-color: #cc241d;
}
.highlight-success {
  padding: 1px 4px;
  color: #fbf1c7;
  border-radius: 2px;
  background-color: #689d6a;
}
.background-message {
  font-weight: bold;
  color: #bdae93;
}
.tooltip .tooltip-inner {
  line-height: 1;
  padding: .75em;
  white-space: nowrap;
  max-width: none;
  background-color: #98971a;
  color: #282828;
}
.tooltip .keystroke {
  padding: .15em .4em;
  margin: 0 -0.3em 0 0.25em;
  border-radius: 2px;
  color: #d5c4a1;
  background: #3c3836;
}
.tooltip.top .tooltip-arrow {
  border-top-color: #98971a;
}
.tooltip.top-left .tooltip-arrow {
  border-top-color: #98971a;
}
.tooltip.top-right .tooltip-arrow {
  border-top-color: #98971a;
}
.tooltip.right .tooltip-arrow {
  border-right-color: #98971a;
}
.tooltip.left .tooltip-arrow {
  border-left-color: #98971a;
}
.tooltip.bottom .tooltip-arrow {
  border-bottom-color: #98971a;
}
.tooltip.bottom-left .tooltip-arrow {
  border-bottom-color: #98971a;
}
.tooltip.bottom-right .tooltip-arrow {
  border-bottom-color: #98971a;
}
.tree-view-resizer {
  border-right: 1px solid #1d2021;
}
.tree-view-scroller {
  overflow-x: hidden;
}
.tree-view {
  color: #d5c4a1;
  background-color: #282828;
}
.tree-view .list-item.selected {
  color: #d5c4a1;
}
.tree-view .list-item:not(.status-modified) {
  color: #d5c4a1;
}
.ColorPicker .ColorPicker-body {
  background: #504945;
}
.ColorPicker .ColorPicker-format {
  background: #504945;
}
.ColorPicker .ColorPicker-format-button {
  background: #504945;
  color: #d5c4a1;
  text-shadow: unset;
  box-shadow: unset;
}
.ColorPicker .ColorPicker-format-button.is--active {
  background: #665c54;
}
